class Solution:
    def minOperations(self, nums1, nums2):
        n = len(nums1)
        total = 1
        for i in range(n):
            total += abs(nums2[i] - nums1[i])
        target = nums2[n]
        best = None
        for i in range(n):
            lo = nums1[i] if nums1[i] < nums2[i] else nums2[i]
            hi = nums1[i] if nums1[i] > nums2[i] else nums2[i]
            if target < lo:
                c = lo - target
            elif target > hi:
                c = target - hi
            else:
                c = 0
            if best is None or c < best:
                best = c
        return total + best

