var minOperations = function(nums1, nums2) {
    const n = nums1.length;
    let total = 1;
    for (let i = 0; i < n; i++) total += Math.abs(nums2[i] - nums1[i]);
    const target = nums2[n];
    let best = Infinity;
    for (let i = 0; i < n; i++) {
        const lo = Math.min(nums1[i], nums2[i]);
        const hi = Math.max(nums1[i], nums2[i]);
        let c;
        if (target < lo) c = lo - target;
        else if (target > hi) c = target - hi;
        else c = 0;
        if (c < best) best = c;
    }
    return total + best;
};
